import{_ as o,c as d,o as c,ae as a}from"./chunks/framework.DfgEVOTW.js";const u=JSON.parse('{"title":"概念与约定","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts.md","filePath":"guide/concepts.md"}'),t={name:"guide/concepts.md"};function l(i,e,r,s,n,h){return c(),d("div",null,[...e[0]||(e[0]=[a(`<h1 id="概念与约定" tabindex="-1">概念与约定 <a class="header-anchor" href="#概念与约定" aria-label="Permalink to &quot;概念与约定&quot;">​</a></h1><h2 id="从-excel-到-table" tabindex="-1">从 Excel 到 Table <a class="header-anchor" href="#从-excel-到-table" aria-label="Permalink to &quot;从 Excel 到 Table&quot;">​</a></h2><ul><li><code>readAndTranslate(path, { plugins }, context)</code> 负责读取工作簿、抽象为 Table，并依次执行插件（如 <code>tableSchema</code>、<code>tableConvert</code>）。</li><li>Table 是 Excel 的最小抽象单元，插件按需为其附加中间产物与最终结果。</li></ul><h2 id="table-内部结构" tabindex="-1">Table 内部结构 <a class="header-anchor" href="#table-内部结构" aria-label="Permalink to &quot;Table 内部结构&quot;">​</a></h2><p>初始 Table 包含：</p><ul><li><code>cols: string[]</code>：列名（A、B、C...）</li><li><code>data: { [row: string]: { [col: string]: Cell } }</code>：行列索引到单元格的映射</li><li><code>getValue(table, row, col)</code>：对 <code>data</code> 的统一读取入口</li></ul><p>插件会在此基础上拓展属性，如 <code>rows/erows/colMap/marks/markCols/markLine/descLine/markList/schema/convert/...</code>。</p><h2 id="标记区域定位" tabindex="-1">标记区域定位 <a class="header-anchor" href="#标记区域定位" aria-label="Permalink to &quot;标记区域定位&quot;">​</a></h2><ul><li>标记行是<strong>真正出现 <code>@</code> 的那一行</strong>，不要求在首行。<code>tableMark</code> 会遍历单元格找到 <code>@</code> 并记录其行列。</li><li>标记行下方一行视为描述行（字段名与注释来源）。</li><li><code>tableDesc</code> 会将标记行的每一列读取为单独的 <strong>语法 token</strong> 并生成 <code>markCols</code>（有效列）与 <code>markLine</code>/<code>descLine</code>。</li><li>Token 被顺序组合成类型表达式，因此 <code>Array</code>、<code>&lt;</code>、<code>&gt;</code>、<code>[</code>、<code>]</code>、<code>{</code>、<code>}</code>、<code>Pair</code> 等符号都要各占一个单元格。</li></ul><p>典型布局（节选）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>等级   数值   ...</span></span>
<span class="line"><span>@      Array  &lt;  Map  &lt;  number  &gt;  &gt;  string  string  ...</span></span>
<span class="line"><span>ID     value        ...                    describe ...</span></span></code></pre></div><h2 id="常用类型语法" tabindex="-1">常用类型语法 <a class="header-anchor" href="#常用类型语法" aria-label="Permalink to &quot;常用类型语法&quot;">​</a></h2><table tabindex="0"><thead><tr><th>写法（按列拆分）</th><th>说明</th></tr></thead><tbody><tr><td><code>@</code></td><td>当前列用于拼接 TID（主键）</td></tr><tr><td><code>uint</code> / <code>int</code> / <code>float</code> / <code>string</code> / <code>bool</code> / <code>tid</code></td><td>基础类型，由 <code>@khgame/schema</code> 提供</td></tr><tr><td><code>Array</code> <code>&lt;</code> <code>T</code> <code>&gt;</code> 或直接 <code>Array&lt;T&gt;</code></td><td>动态数组，转换结果为 <code>T[]</code></td></tr><tr><td><code>[</code> <code>T</code> <code>]</code></td><td>与 <code>Array&lt;T&gt;</code> 等价，常用于短写</td></tr><tr><td><code>{</code> <code>...</code> <code>}</code></td><td>对象字面量，字段名来自描述行</td></tr><tr><td><code>Pair</code> <code>&lt;</code> <code>T</code> <code>&gt;</code></td><td>二元组，转换为 <code>{ key: string, val: T }</code>，常用于 <code>key:value</code> 形式数据</td></tr><tr><td><code>Map</code> <code>&lt;</code> <code>T</code> <code>&gt;</code></td><td>逻辑 Map（本质是 <code>Pair&lt;T&gt;[]</code>），序列化时可据上下文转为对象或数组</td></tr><tr><td><code>A</code> \`</td><td><code></code>B\`</td></tr><tr><td><code>T</code> <code>?</code></td><td>可选类型</td></tr><tr><td><code>$oneof</code> <code>[</code> <code>...</code> <code>]</code></td><td>限制枚举值的联合</td></tr></tbody></table><blockquote><p><strong>Pair / Map</strong>：输入通常写成 <code>key:value</code> 形式字符串。Pair 代表单条键值，Map 则表示键值对数组，可在序列化阶段转换为对象或保持数组结构。</p></blockquote><h2 id="装饰器" tabindex="-1">装饰器 <a class="header-anchor" href="#装饰器" aria-label="Permalink to &quot;装饰器&quot;">​</a></h2><p>装饰器写在结构体符号之前，占用独立单元格：</p><ul><li><code>$strict</code> <code>[</code> ... <code>]</code>：强制数组大小与声明一致</li><li><code>$ghost</code> <code>{ ... }</code>：生成 Schema，但在导出数据时忽略对应字段</li><li><code>$ghost{</code> ... <code>}</code>：常用于为数组元素中的字段提供补充 Schema</li><li>其他装饰器由 <code>@khgame/schema</code> 解析，遵循相同的 token 拆分规则</li></ul><h2 id="描述行与数据行" tabindex="-1">描述行与数据行 <a class="header-anchor" href="#描述行与数据行" aria-label="Permalink to &quot;描述行与数据行&quot;">​</a></h2><ul><li>描述行（标记行下一行）为每列提供字段名和注释。</li><li>数据行从标记行下<strong>两行</strong>开始，<code>tableEnsureRows</code> 会剔除全空行，<code>tableConvert</code> 依据 <code>markCols</code> 和 <code>getValue</code> 还原每行数据。</li><li>字符串类型列若单元格为空，会在转换阶段标准化为 <code>&#39;&#39;</code>，避免 <code>string required</code> 报错；其他类型需保证符合声明。</li></ul><p>示例（节选）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A: @     B: uint      C: string      D: $strict [ { tid:uint; num:float } ]  E: Array&lt;Pair&lt;uint&gt;&gt;  ...</span></span>
<span class="line"><span>A: id    B: level     C: name        D: product                            E: rewards             ...</span></span>
<span class="line"><span>001      1            farm           [{tid:1000001,num:1}]                 [ [1,2] ]             ...</span></span>
<span class="line"><span>001      2            farm           [{tid:1000001,num:2}]                 [ [1,3] ]             ...</span></span></code></pre></div><p><code>...</code> 表示该工作表还可以追加更多列，例如资源成本 <code>Map&lt;uint&gt;</code>、嵌套数组 <code>[</code> <code>[</code> <code>int</code> ...，所有列都会参与 Schema 解析与数据生成。</p><h2 id="schema-与序列化" tabindex="-1">Schema 与序列化 <a class="header-anchor" href="#schema-与序列化" aria-label="Permalink to &quot;Schema 与序列化&quot;">​</a></h2><ul><li><code>tableSchema</code> 调用 <code>@khgame/schema</code> 将 <code>markList</code> 解析为 AST，生成 TS 接口或上下文信息（枚举、联合等）。</li><li><code>tsInterfaceSerializer</code>、<code>tsSerializer</code>、<code>jsonSerializer</code> 等会使用 Schema 和数据生成目标产物；接口名称通过描述行和 <code>makeInterfaceName</code> 计算。</li></ul><h2 id="数据转换与策略" tabindex="-1">数据转换与策略 <a class="header-anchor" href="#数据转换与策略" aria-label="Permalink to &quot;数据转换与策略&quot;">​</a></h2><ul><li><code>tableConvert</code> 会基于 Schema 生成 <code>convert = { tids, result, collisions }</code>： <ul><li><code>tids</code>：按 <code>@</code> 列拼接出的主键</li><li><code>result</code>：<code>tid -&gt; 行数据</code> 映射</li><li><code>collisions</code>：TID 冲突时记录首条和新条数据</li></ul></li><li>冲突策略（<code>context.policy.tidConflict</code>）： <ul><li><code>error</code>（默认）抛错</li><li><code>overwrite</code> 用后者覆盖前者</li><li><code>ignore</code> 丢弃后者</li><li><code>merge</code> 深合并对象</li></ul></li><li>CLI <code>--strict</code> 会强制 <code>error</code> 策略，避免静默覆盖。</li></ul><h2 id="产出稳定性" tabindex="-1">产出稳定性 <a class="header-anchor" href="#产出稳定性" aria-label="Permalink to &quot;产出稳定性&quot;">​</a></h2><ul><li>所有序列化器会在输出前对 <code>result</code> 的键排序，保证重复构建的产物差异最小化。</li></ul><p>更多：见 <a href="./plugins.html">插件与扩展点</a> · <a href="./serializers.html">序列化器与上下文</a>。</p>`,29)])])}const m=o(t,[["render",l]]);export{u as __pageData,m as default};
